  const expectedHeader = `CustomToken ${expectedToken}`;

  context.log.info(`Auth Header: ${authHeader}`);
  context.log.info(`Expected Header: ${expectedHeader}`);
  context.log.info(`Run ID from options: ${runId}`);

  if (authHeader !== expectedHeader) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401,
      headers: {
        "content-type": "application/json",
      },
    });
  }

  return request;
}

